from datetime import datetime
from elasticsearch import Elasticsearch
import json

es = Elasticsearch([{'host': 'localhost', 'port': 9200}])
index_name = "logs"
doc_type = "_doc"

# Function to index a log document
def index_log(doc_id, doc):
    res = es.index(index=index_name, id=doc_id, body=doc)
    return res['result']

# Function to search logs
def search_logs(query):
    res = es.search(index=index_name, body={"query": {"multi_match": {"query": query, "fields": ["message"]}}})
    return res["hits"]["hits"]

# Function to aggregate logs by timestamp
def aggregate_logs(start_time, end_time):
    size = 0
    aggs = {
        "date_range": {
            "range": {
                "timestamp": {"format": "yyyy-MM-dd'T'HH:mm:ss", "fielddata_fields": ["@timestamp"]}
            },
            "aggs": {
                "logs_by_date": {
                    "terms": {"field": "@timestamp.keyword"}
                }
            }
        }
    }
    res = es.search(index=index_name, body={"size": 0, "query": {}, "aggs": aggs})
    aggregations = res["aggregations"]["date_range"]
    for bucket in aggregations["buckets"]:
        start = datetime.strptime(bucket["key_as_string"], "%Y-%m-%dT%H:%M:%S")
        if start >= start_time and start <= end_time:
            size += len(bucket["logs_by_date"]["buckets"])
    return size

